cd /tmp/pi-github-repos/paper-design/paper-mono && otfinfo --info fonts/ttf/PaperMono-Bold.ttf 2>/dev/null | head -5 || python3 -c "
from fontTools.ttLib import TTFont
import sys
try:
    font = TTFont('fonts/ttf/PaperMono-Bold.ttf')
    name_table = font['name']
    for record in name_table.names:
        if record.nameID == 1:
            print(f'Family: {record.toUnicode()}')
        if record.nameID == 2:
            print(f'Subfamily: {record.toUnicode()}')
        if record.nameID == 4:
            print(f'Full Name: {record.toUnicode()}')
except Exception as e:
    print(f'Error: {e}')
" 2>/dev/null || fc-scan fonts/ttf/PaperMono-Bold.ttf 2>/dev/null | grep -E "family|style" | head -5

python3 -c "
from fontTools.ttLib import TTFont
font = TTFont('/tmp/pi-github-repos/paper-design/paper-mono/fonts/ttf/PaperMono-Regular.ttf')
for r in font['name'].names:
    if r.nameID in (1,2,4,16,17):
        print(f'nameID {r.nameID}: {r.toUnicode()}')
print('---')
font2 = TTFont('/tmp/pi-github-repos/paper-design/paper-mono/fonts/ttf/PaperMono-Bold.ttf')
for r in font2['name'].names:
    if r.nameID in (1,2,4,16,17):
        print(f'nameID {r.nameID}: {r.toUnicode()}')
"
